func (m bookingEntryMods) WithParentsCascading() BookingEntryMod {
	return BookingEntryModFunc(func(ctx context.Context, o *BookingEntryTemplate) {
		if isDone, _ := bookingEntryWithParentsCascadingCtx.Value(ctx); isDone {
			return
		}
		ctx = bookingEntryWithParentsCascadingCtx.WithValue(ctx, true)
		{

			related := o.f.NewDriverWithContext(ctx, DriverMods.WithParentsCascading())
			m.WithDriver(related).Apply(ctx, o)
		}
		{

			related := o.f.NewEventWithContext(ctx, EventMods.WithParentsCascading())
			m.WithEvent(related).Apply(ctx, o)
		}
		{

			related := o.f.NewRaceGridWithContext(ctx, RaceGridMods.WithParentsCascading())
			m.WithRaceGrid(related).Apply(ctx, o)
		}
		{

			related := o.f.NewRaceWithContext(ctx, RaceMods.WithParentsCascading())
			m.WithRace(related).Apply(ctx, o)
		}
		{

			related := o.f.NewTeamWithContext(ctx, TeamMods.WithParentsCascading())
			m.WithTeam(related).Apply(ctx, o)
		}
	})
}

